function extractPanchayatDetails(workAllotmentData, tr) {
    var columns = jQuery(tr).find("td");
    var state = jQuery(jQuery(columns)[0]).text().replace("State", "").replace(":", "").trim();
    var district = jQuery(jQuery(columns)[1]).text().replace("District", "").replace(":", "").trim();
    var block = jQuery(jQuery(columns)[2]).text().replace("Block", "").replace(":", "").trim();
    var panchayat = jQuery(jQuery(columns)[3]).text().replace("Panchayat", "").replace(":", "").trim();
    var fy = jQuery(jQuery(columns)[4]).text().replace("Financial Year", "").replace(":", "").trim();
    console.log(state + ":" + district + ":" + block + ":" + panchayat + ":" + fy);
    workAllotmentData["gp_name"] = panchayat;
    workAllotmentData["gp_block"] = block;
    workAllotmentData["gp_district"] = district;
    workAllotmentData["gp_state"] = state;
    workAllotmentData["fy"] = fy;
}

function isWorkCodeRow(tr) {
    if (jQuery(tr).find("#ctl00_ContentPlaceHolder1_lblWorkName").length > 0) {
        return true;
    } else {
        return false;
    }
}

function extractWorkCodeDetails(workAllotmentData, tr) {
    var workText = jQuery(tr).find("#ctl00_ContentPlaceHolder1_lblWorkName").text().replace("Work Name", "").replace("(work Code)", "").replace(":", "").trim();
    var workName = workText.substring(0, workText.lastIndexOf("("));
    var workCode = workText.substring(workText.lastIndexOf("(") + 1).replace(")", "").trim();
    console.log(workName + ":" + workCode);
    workAllotmentData["work_name"] = workName;
    workAllotmentData["work_code"] = workCode;

}

function isStartOfWorkGroup(tr) {
    if (jQuery(tr).text().trim() == "List  of person to whom Work Alloted" || jQuery(tr).text().trim() == "List of person to whom Work Alloted") {
        return true;
    }
}

function isApplicantRow(tr) {
    if (jQuery(jQuery(tr).find("span[id*=ctl00_]")).length > 4) {
        return true;
    }
    return false;
}

function getApplicantDetails(tr) {
    var applicantDetails = {};
    applicantDetails["reg_number"] = jQuery(jQuery(tr).find("span")[0]).text().trim();
    applicantDetails["name"] = jQuery(jQuery(tr).find("span")[1]).text().trim();
    applicantDetails["from_date"] = jQuery(jQuery(tr).find("span")[2]).text().trim();
    applicantDetails["number_of_days"] = jQuery(jQuery(tr).find("span")[3]).text().trim();
    applicantDetails["to_date"] = jQuery(jQuery(tr).find("span")[4]).text().trim();
    return applicantDetails;
}


function parseWorkAllocationSheet(table) {
    var applicants = [];
    var applicantsGroup = [];
    var workAllotmentData = {}
    jQuery(table).find("tr").each(function (i, tr) {
        if (i > 1) {
            if (i == 2) {
                extractPanchayatDetails(workAllotmentData, tr);
            }
            if (isWorkCodeRow(tr)) {
                extractWorkCodeDetails(workAllotmentData, tr);
            }
            if (localStorage.gp_details) {
                var stored_gp = JSON.parse(localStorage.gp_details);
                if (workAllotmentData.gp_name.trim() == gp_hash[stored_gp.panchayat_code].panchayat_name.trim() && workAllotmentData.fy == stored_gp.fin_year) {
                    if (isStartOfWorkGroup(tr)) {
                        if (applicantsGroup.length > 0) {
                            applicants.push(applicantsGroup);
                        }
                        applicantsGroup = [];
                    }
                    if (isApplicantRow(tr)) {
                        var applicantDetails = getApplicantDetails(tr);
                        if (applicantDetails["name"]) {
                            applicantsGroup.push(getApplicantDetails(tr));
                        }
                    }
                }
            } else if (localStorage.agency_details) {
                var stored_agency = JSON.parse(localStorage.agency_details);
                stored_agency.fin_year = localStorage.fin_year;
                workAllotmentData.stored_agency = stored_agency;
                if (workAllotmentData.fy == stored_agency.fin_year) {
                    if (isStartOfWorkGroup(tr)) {
                        if (applicantsGroup.length > 0) {
                            applicants.push(applicantsGroup);
                        }
                        applicantsGroup = [];
                    }
                    if (isApplicantRow(tr)) {
                        var applicantDetails = getApplicantDetails(tr);
                        if (applicantDetails["name"]) {
                            applicantsGroup.push(getApplicantDetails(tr));
                        }
                    }
                }
            }
        }
    });
    console.log("App Group");
    console.log(applicantsGroup);
    if (applicantsGroup.length > 0) {
        applicants.push(applicantsGroup);
        applicantsGroup = []
    }
    console.log(applicants);
    workAllotmentData["applicants"] = applicants;
    return workAllotmentData;
}

function errorHandler(e) {
    console.log("Error occurred");
    console.log(e);
}

function onReadFs(fs) {
    fs.root.getFile('saved_work_allocation.txt', { create: true }, function (fileEntry) {

        fileEntry.file(function (file) {
            var reader = new FileReader();

            reader.onloadend = function (e) {
                currentFileData = this.result;
                console.log(currentFileData);
                if (currentFileData) {
                    console.log(JSON.parse(currentFileData));
                } else {
                    currentFileData = "{}";
                }
                var currentFileJSON = JSON.parse(currentFileData);
                sendFileData(currentFileJSON);
            };
            reader.readAsText(file);
        }, errorHandler);
    });
}
function onInitFs(fs) {

    fs.root.getFile('saved_work_allocation.txt', { create: true }, function (fileEntry) {

        fileEntry.file(function (file) {
            var reader = new FileReader();

            reader.onloadend = function (e) {
                currentFileData = this.result;
                if (currentFileData) {
                    console.log(JSON.parse(currentFileData));
                } else {
                    currentFileData = "{}";
                }
                // Create a FileWriter object for our FileEntry (log.txt).
                fileEntry.createWriter(function (fileWriter) {

                    fileWriter.onwriteend = function (e) {
                        console.log('Write completed.');
                    };

                    fileWriter.onerror = function (e) {
                        console.log('Write failed: ' + e.toString());
                    };
                    var currentFileJSON = JSON.parse(currentFileData);
                    var time = new Date().getTime();
                    currentFileJSON[time] = workAllotmentData;
                    // Create a new Blob and write it to log.txt.
                    var blob = new Blob([JSON.stringify(currentFileJSON)], { type: 'text/plain' });

                    fileWriter.write(blob);

                }, errorHandler);
            };

            reader.readAsText(file);
        }, errorHandler);

    }, errorHandler);

}

