function retainNeededApplicants(allocationData) {
    $(allocationData.applicants).each(function (i, applicantGroup) {
        allocationData.applicants[i] = applicantGroup.filter(function (applicant) {
            return applicant.form_needed;
        });
        console.log(allocationData.applicants[i]);
        console.log("---");
    });
    console.log(allocationData);
    return allocationData;
}
function appendAllotmentFormToPDF(allotmentData, doc, template, index) {
    var applicants = allotmentData.applicants;
    var applicant = applicants[index];
    var templateData = jQuery.extend(true, {}, allotmentData);
    templateData.applicants = [];
    jQuery(applicants).each(function (i, applicant) {
        if (applicant.name.indexOf("(") >= 0) {
            applicant.name = applicant.name.substring(0, applicant.name.lastIndexOf("("));
        }
        applicant.application_date = moment(applicant.application_date).format("DD/MM/YYYY");
        applicant.form9Date = moment(applicant.form9Date).format("DD/MM/YYYY");
        applicant.from_date = moment(applicant.from_date).format("DD/MM/YYYY");
        applicant.to_date = moment(applicant.to_date).format("DD/MM/YYYY");
        if (i == 0 || (i > 0 && applicant.reg_number != applicants[i - 1].reg_number)) {
            templateData.applicants.push({ "applicant": applicant });
        } else {
            templateData.applicants[templateData.applicants.length - 1].applicant.name += ", " + applicant.name;
        }
    })
    console.log("Final data");
    console.log(templateData);
    var scale = 3;
    if (templateData.applicants.length > 10) {
        scale = 2;
    }
    var opt = {
        margin: [0.5, 0.5],
        filename: 'allotmentForm - ' + allotmentData.work_code.substring(allotmentData.work_code.length - 5, allotmentData.work_code.length) + '.pdf',
        image: { type: 'jpeg', quality: 1.0 },
        html2canvas: { scale: scale },
        jsPDF: { unit: 'in', format: 'letter', orientation: 'portrait' }
    };

    var pages = [];
    jQuery(templateData.applicants).each(function (index, applicant) {
        var nData = jQuery.extend(true, {}, templateData);
        nData.applicants = [templateData.applicants[index]];
        pages.push(template(nData));
    })
    var worker = html2pdf().set(opt).from(pages[0]).toPdf();
    pages.slice(1).forEach(function (page) {
        worker = worker.get('pdf').then(function (pdf) {
            pdf.addPage();
        }).from(page).toContainer().toCanvas().toPdf();
    });
    worker = worker.save().then(function (obj) {

    });
    /*html2canvas(document.body, {
      onrendered: function(canvas) {
        var img = canvas.toDataURL("image/jpeg");
        //jQuery(document.body).append('<img src="' + img + '"/>');
        doc.addImage(img, 'JPEG', 0, 0);
        //doc.save('test15.pdf');
        if(index < applicants.length - 1) {
          doc.addPage();
          appendAllotmentFormToPDF(allotmentData, doc, template, index+1);
        }else {
          saveWorkAllotmentPDF(doc);
        }
      }
    });*/

}

function getAllotmentData(allocationData) {
    var allotmentData = allocationData;
    var applicants = [];
    $(allocationData.applicants).each(function (i, applicantGroup) {
        $(applicantGroup).each(function (i, applicant) {
            if (applicant.form_needed) {
                applicants.push(applicant);
            }
        });
    });
    allotmentData.applicants = applicants;
    console.log(allotmentData);
    return allotmentData;
}
