function getHiddenFieldVal(fieldName, data) {
    var sIndex = data.indexOf(fieldName + "|") + fieldName.length + 1;
    var eIndex = data.indexOf("|", sIndex);
    return data.substring(sIndex, eIndex)
}

function getHiddenDynSalt(data) {
    var fieldName = 'ContentPlaceHolder1_dynSalt" value="';
    var sIndex = data.indexOf(fieldName) + fieldName.length;
    var eIndex = data.indexOf('"', sIndex);
    return data.substring(sIndex, eIndex)
}

function getData(mgr1, eventTarget, eventArgument, lastFocus, viewState, viewStateGenerator, viewStateEncrypted, eventValidation, dynSalt, year, district, block, panchayat, extraData) {
    var data = {
        "ctl00$ScriptManager1": mgr1,
        "__EVENTTARGET": eventTarget,
        "__EVENTARGUMENT": eventArgument,
        "__LASTFOCUS": lastFocus,
        "__VIEWSTATE": viewState,
        "__VIEWSTATEGENERATOR": viewStateGenerator,
        "__VIEWSTATEENCRYPTED": viewStateEncrypted,
        "__EVENTVALIDATION": eventValidation,
        "ctl00$ContentPlaceHolder1$dynSalt": dynSalt,
        "ctl00$ContentPlaceHolder1$ddlFin": year,
        "ctl00$ContentPlaceHolder1$ddldist": district,
        "ctl00$ContentPlaceHolder1$ddlblock": block,
        "ctl00$ContentPlaceHolder1$ddlpanchayat": panchayat,
        "__ASYNCPOST": true
    }
    if (extraData) {
        $(Object.keys(extraData)).each(function (i, key) {
            data[key] = extraData[key];
        });
    }
    return data;
}
