function doAjaxRequest(url, successCallback, errorCallback) {
    $.ajax({
        type: "GET",
        url: url,

        success: function (data) {
            console.log("Success");
            successCallback(data);
        },
        error: function (xhr, status, reason) {
            console.log("Error");
            console.log(status);
            console.log(reason);
            console.log(xhr);
        }
    });
}

function parseWorkList(table) {
    var workList = [];
    jQuery(table).find("tr").each(function (i, tr) {
        if (i > 1) {
            var workDetail = {

            }
            jQuery(tr).find("td").each(function (i, td) {
                if (i == 5) {
                    workDetail.url = jQuery(td).find("a").attr("href");
                    var colText = jQuery(td).find("font").text().trim();
                    workDetail.name = colText.substring(0, colText.lastIndexOf("(")).trim();
                    workDetail.code = colText.substring(colText.lastIndexOf("(") + 1, colText.length - 1).trim();
                } else if (i == 6) {
                    workDetail.category = jQuery(td).text().trim();
                } else if (i == 7) {
                    workDetail.executing_agency = jQuery(td).text().trim();
                } else if (i == 8) {
                    workDetail.est_labour = jQuery(td).text().trim();
                } else if (i == 9) {
                    workDetail.est_material = jQuery(td).text().trim();
                } else if (i == 10) {
                    workDetail.actual_labour = jQuery(td).text().trim();
                } else if (i == 11) {
                    workDetail.actual_material = jQuery(td).text().trim();
                }

            });
            if (workDetail.url) {
                workList.push(workDetail);
            }
        }
    });
    return workList;
}

function parseFTOForMonth(wageListTable, month, successCallback) {
    var fetchList = [];
    $(wageListTable).find("tr").each(function (i, wageRow) {
        if (i > 0) {
            var fto_number_col = $($(wageRow).find("td")[1]).text().trim();
            var mIndex = fto_number_col.indexOf("_") + 1 + 2;
            var monthStr = fto_number_col.substring(mIndex, mIndex + 2);
            if (monthStr == month) {
                var url = "https://mnregaweb4.nic.in/netnrega/FTO/" + $($(wageRow).find("td")[1]).find("a").attr("href");
                fetchList.push({
                    "fto_no": fto_number_col,
                    "url": url
                });
            }
        }
    });

    var fetchCount = 0;
    var ftoTransactions = [];
    $(fetchList).each(function (i, fetchObject) {
        doAjaxRequest(fetchObject.url, function (data) {
            fetchCount = fetchCount + 1;
            parseFTOTransactionDetails($(data).find("table")[3], fetchObject.fto_no, ftoTransactions);
            if (fetchCount == fetchList.length) {
                //sort based on date
                ftoTransactions.sort(function (a, b) {
                    var d1 = moment(a.dateProcessed, "DD/MM/YYYY");
                    var d2 = moment(b.dateProcessed, "DD/MM/YYYY");
                    return d1 - d2;
                })
                successCallback(ftoTransactions);
            }
        });
    });

}

function parseMaterialFTOForMonth(wageListTable, month, successCallback) {
    var fetchList = [];
    $(wageListTable).find("tr").each(function (i, wageRow) {
        if (i > 0) {
            var fto_number_col = $($(wageRow).find("td")[1]).text().trim();
            var mIndex = fto_number_col.indexOf("_") + 1 + 2;
            var monthStr = fto_number_col.substring(mIndex, mIndex + 2);
            if (monthStr == month) {
                var url = "https://mnregaweb4.nic.in/netnrega/FTO/" + $($(wageRow).find("td")[1]).find("a").attr("href");
                fetchList.push({
                    "fto_no": fto_number_col,
                    "url": url
                });
            }
        }
    });

    var fetchCount = 0;
    var ftoTransactions = [];
    $(fetchList).each(function (i, fetchObject) {
        doAjaxRequest(fetchObject.url, function (data) {
            fetchCount = fetchCount + 1;
            parseMaterialFTOTransactionDetails($(data).find("table")[3], fetchObject.fto_no, ftoTransactions);
            if (fetchCount == fetchList.length) {
                //sort based on date
                ftoTransactions.sort(function (a, b) {
                    var d1 = moment(a.dateProcessed, "DD/MM/YYYY");
                    var d2 = moment(b.dateProcessed, "DD/MM/YYYY");
                    return d1 - d2;
                })
                successCallback(ftoTransactions);
            }
        });
    });
    if ($(fetchList).length == 0) {
        successCallback(ftoTransactions);
    }
}


function parseMaterialFTOTransactionDetails(ftoTable, ftoNumber, ftoTransactions) {
    var vendorID = "";
    var vendorName = "";
    var voucherNumber = "";
    var totalProcessed = 0;
    var totalRejected = 0;
    var dateProcessed = "";
    $(ftoTable).find("tr").each(function (i, fToTableRow) {
        if (i > 0) {
            var vName = $($(fToTableRow).find("td")[4]).text().trim();
            if (vName) {
                vendorName = vName;
            }
            if ($($(fToTableRow).find("td")[9]).text().trim() == "Total") {
                totalProcessed = $($(fToTableRow).find("td")[11]).text().trim()
            }
            if ($($(fToTableRow).find("td")[12]).text().trim() == "Rejected") {
                totalRejected += parseInt($($(fToTableRow).find("td")[11]).text().trim());
            }
            if ($($(fToTableRow).find("td")[3]).text().trim()) {
                dateProcessed = $($(fToTableRow).find("td")[3]).text().trim();
            }
            if ($($(fToTableRow).find("td")[5]).text().trim()) {
                vendorID = $($(fToTableRow).find("td")[5]).text().trim();
            }
            if ($($(fToTableRow).find("td")[6]).text().trim()) {
                voucherNumber = $($(fToTableRow).find("td")[6]).text().trim();
            }
        }
    })
    ftoTransactions.push({
        ftoNumber: ftoNumber,
        vendorID: vendorID,
        vendorName: vendorName,
        voucherNumber: voucherNumber,
        dateProcessed: dateProcessed,
        totalProcessed: totalProcessed,
        totalRejected: totalRejected
    });
    return ftoTransactions;
}

function parseFTOTransactionDetails(ftoTable, ftoNumber, ftoTransactions) {
    var wageListNumber = null;
    var totalProcessed = 0;
    var totalRejected = 0;
    var dateProcessed = "";
    $(ftoTable).find("tr").each(function (i, fToTableRow) {
        if (i > 0) {
            var rowWageListNumber = $($(fToTableRow).find("td")[6]).text().trim();
            if (rowWageListNumber) {
                wageListNumber = rowWageListNumber;
            }
            if ($($(fToTableRow).find("td")[9]).text().trim() == "Total") {
                totalProcessed = $($(fToTableRow).find("td")[11]).text().trim()
            }
            if ($($(fToTableRow).find("td")[12]).text().trim() == "Rejected") {
                totalRejected += parseInt($($(fToTableRow).find("td")[11]).text().trim());
            }
            if ($($(fToTableRow).find("td")[4]).text().trim()) {
                dateProcessed = $($(fToTableRow).find("td")[4]).text().trim()
            }
        }
    })
    ftoTransactions.push({
        ftoNumber: ftoNumber,
        wageListNumber: wageListNumber,
        dateProcessed: dateProcessed,
        totalProcessed: totalProcessed,
        totalRejected: totalRejected
    });
    return ftoTransactions;
}

