function parseWorkListFromDPR(table) {
    var workList = [];
    jQuery(table).find("tr").each(function (i, tr) {
        if (i > 1) {
            var workDetail = {

            }
            jQuery(tr).find("td").each(function (i, td) {
                if (i == 1 && jQuery(td).find("a").length > 0) {
                    workDetail.url = encodeURIComponent(jQuery(td).find("a").attr("href"));
                    var colText = jQuery(td).text().trim();
                    workDetail.code = jQuery(td).find("a").text().trim();
                    workDetail.name = colText.replace(workDetail.code, "").replace("(", "").replace(")", "").trim();
                } else if (i == 2) {
                    workDetail.status = jQuery(td).text().trim();
                }
            });
            if (workDetail.url) {
                workList.push(workDetail);
            }
        }
    });
    return workList;
}

