async function genPdf(data, fileName) {
    const nDoc = await PDFLib.PDFDocument.load(data);
    const newDoc = await PDFLib.PDFDocument.create();
    //const newPage = newDoc.addPage();
    const totalPages = nDoc.getPageCount();
    const [existingPage] = await newDoc.copyPages(nDoc, [0])
    newDoc.addPage(existingPage)
    for (var i = 0; i < Math.floor(totalPages / 2); i++) {
        const [existingPage] = await newDoc.copyPages(nDoc, [i + 1]);
        newDoc.addPage(existingPage);
        if (i < (totalPages / 2 - 1)) {
            const [existingPage1] = await newDoc.copyPages(nDoc, [Math.floor(totalPages / 2) + (i + 1)]);
            newDoc.addPage(existingPage1)
        }
    }
    const pdfBytes = await newDoc.save();
    var blob = new Blob([pdfBytes], { type: 'application/pdf' });
    var a = document.createElement('a');
    a.href = window.URL.createObjectURL(blob);
    a.download = fileName;
    a.style.position = 'fixed';
    a.target = '_blank';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);

}

