function parseWorkDetailFromDPR(document) {
    var workCategory = jQuery(document).find("#ContentPlaceHolder1_catlbl").text().trim();
    var workDetails = jQuery(document).find("#ContentPlaceHolder1_wrklbl").text().trim();
    var workCode = workDetails.substring(0, workDetails.indexOf("("));
    var workName = workDetails.substring(workDetails.indexOf("(") + 1, workDetails.length).replace(")", "");
    var fy = jQuery(document).find("#ContentPlaceHolder1_lblfin_text").text().trim();
    var executionLevel = jQuery(document).find("#ContentPlaceHolder1_ExeLevel_text").text().trim();
    var executionAgency = jQuery(document).find("#ContentPlaceHolder1_lbl_agency_text").text().trim();
    var workStatus = jQuery(document).find("#ContentPlaceHolder1_lblworkstatus_text").text().trim();
    var proposalDate = jQuery(document).find("#ContentPlaceHolder1_LblProdate").text().trim();
    var workStartDate = jQuery(document).find("#ContentPlaceHolder1_LblWrksdate").text().trim();
    var presentState = jQuery(document).find("#ContentPlaceHolder1_Lblprestatus").text().trim();
    var proposedState = jQuery(document).find("#ContentPlaceHolder1_Lblpostatus").text().trim();
    var techSanctionNumber = jQuery(document).find("#ContentPlaceHolder1_lblsanctionno_text").text().trim();
    var sanctionDate = jQuery(document).find("#ContentPlaceHolder1_lblsandate_text").text().trim();
    var estUnskilled = jQuery(document).find("#ContentPlaceHolder1_lblSanc_Tech_Labr_Unskilled").text().trim();
    var estMaterialCost = jQuery(document).find("#ContentPlaceHolder1_lbltot_mat").text().trim();
    var estTotalCost = jQuery(document).find("#ContentPlaceHolder1_lblEst_Cost_Tota").text().trim();
    var mnregaSactionAmount = jQuery(document).find("#ContentPlaceHolder1_lblsanc_fin_Amt").text().trim();
    var financialAdminSactionNumber = jQuery(document).find("#ContentPlaceHolder1_Lblsanc_fin_no").text().trim();
    var financialAdminSactionDate = jQuery(document).find("#ContentPlaceHolder1_Lblsanc_fin_dt").text().trim();
    var work = {
        workCategory: workCategory,
        workCode: workCode,
        workName: workName,
        fy: fy,
        executionLevel: executionLevel,
        executionAgency: executionAgency,
        workStatus: workStatus,
        proposalDate: proposalDate,
        workStartDate: workStartDate,
        presentState: presentState,
        proposedState: proposedState,
        techSanctionNumber: techSanctionNumber,
        sanctionDate: sanctionDate,
        estUnskilled: estUnskilled,
        estMaterialCost: estMaterialCost,
        estTotalCost: estTotalCost,
        mnregaSactionAmount: mnregaSactionAmount,
        financialAdminSactionNumber: financialAdminSactionNumber,
        financialAdminSactionDate: financialAdminSactionDate
    }
    return work;
}

