function parseWorkDetail(table) {
    var workDetail = {};
    jQuery(table).find("tr").each(function (i, tr) {
        var colText = jQuery(jQuery(tr).find("td")[0]).text().trim()
        if (colText.indexOf("Work Name") >= 0) {
            var workCol = jQuery(tr).find("td")[1];
            var workName = jQuery(jQuery(workCol).find("font")[1]).text().trim();
            var workCode = jQuery(jQuery(workCol).find("font")[0]).text().trim();
            workDetail.work_code = workCode;
            workDetail.work_name = workName;
        }
        else if (colText.indexOf("Nature of Work") >= 0) {
            workDetail.work_nature = jQuery(jQuery(tr).find("td")[1]).text().trim();
        }
        else if (colText.indexOf("ಕಾಮಗಾರಿ ಹಂತ") >= 0) {
            workDetail.status = jQuery(jQuery(tr).find("td")[1]).text().trim();
        }
        else if (colText.indexOf("Scope of Work") >= 0) {
            jQuery(tr).find("table tr").each(function (innerRowIndex, innerRow) {
                if (innerRowIndex == 1) {
                    jQuery(innerRow).find("td").each(function (innerColIndex, innerCol) {
                        if (innerColIndex == 0) {
                            workDetail.start_status = jQuery(innerCol).text().trim();
                        } else if (innerColIndex == 1) {
                            workDetail.end_status = jQuery(innerCol).text().trim();
                        }
                    })
                }
            })
        }
        else if (colText.indexOf("Location") >= 0) {
            jQuery(tr).find("table tr").each(function (innerRowIndex, innerRow) {
                if (innerRowIndex == 0) {
                    jQuery(innerRow).find("td").each(function (innerColIndex, innerCol) {
                        if (innerColIndex == 0) {

                        } else if (innerColIndex == 1) {
                            workDetail.start_location = jQuery(innerCol).text().trim();
                        }
                    })
                } else if (innerRowIndex == 2) {
                    jQuery(innerRow).find("td").each(function (innerColIndex, innerCol) {
                        if (innerColIndex == 0) {
                            workDetail.khata_number = jQuery(innerCol).text().trim();
                        } else if (innerColIndex == 1) {
                            workDetail.plot_number = jQuery(innerCol).text().trim();
                        }
                    })
                }
            })
        }
        else if (colText.indexOf("Sanction No.") >= 0) {
            var sanctionText = jQuery(jQuery(tr).find("td")[0]).text().trim().replace("Sanction No. and Sanction Date", "").trim().replace(":", "").trim();
            var sactionNumber = sanctionText.split(",")[0].trim();
            var sactionDate = sanctionText.split(",")[1].trim();
            workDetail.sanction_number = sactionNumber;
            workDetail.saction_date = sactionDate;

        }

        else if (colText.indexOf("Distinct Number of Muster Rolls used(Amount)") >= 0) {
            var muster_rolls = jQuery(jQuery(tr).find("td")[1]).find("a");
            workDetail.muster_rolls = []
            jQuery(muster_rolls).each(function (mIndex, mAnchor) {
                var muster_roll = {
                    id: jQuery(mAnchor).text(),
                    url: mAnchor.href
                }
                workDetail.muster_rolls.push(muster_roll);
            })
        }

        else if (colText.indexOf("Work start date") >= 0) {
            workDetail.work_start_date = jQuery(jQuery(tr).find("td")[1]).text().trim();
        }

    });
    return workDetail;
}
