function exportWorkAllocations(callback) {
    sendFileData = function (jsonData) {
        var blob = new Blob([JSON.stringify(jsonData)], { type: "text/json" });
        var url = URL.createObjectURL(blob);
        chrome.downloads.download({
            filename: "nDocusoftExport.json",
            url: url // The object URL can be used as download URL
        });
    }
    window.webkitRequestFileSystem(window.PERSISTENT, 2048 * 2048, onReadFs, errorHandler);
}

function importWorkAllocations(gpId, allocationData, callback) {
    window.webkitRequestFileSystem(window.PERSISTENT, 2048 * 2048, function (fs) {
        fs.root.getFile('saved_work_allocation.txt', { create: true }, function (fileEntry) {

            fileEntry.file(function (file) {
                var reader = new FileReader();

                reader.onloadend = function (e) {
                    currentFileData = this.result;
                    if (currentFileData) {
                        console.log(JSON.parse(currentFileData));
                    } else {
                        currentFileData = "{}";
                    }
                    // Create a FileWriter object for our FileEntry (log.txt).
                    fileEntry.createWriter(function (fileWriter) {

                        fileWriter.onwriteend = function (e) {
                            console.log('Write completed.');
                        };

                        fileWriter.onerror = function (e) {
                            console.log('Write failed: ' + e.toString());
                        };
                        var currentFileJSON = JSON.parse(currentFileData);

                        console.log("Allocation data");
                        console.log(allocationData);
                        jQuery.each(allocationData, function (key, value) {
                            console.log(value);
                            console.log(key);
                            var time = key;
                            currentFileJSON[time] = value;
                        })
                        // Create a new Blob and write it to log.txt.
                        var blob = new Blob([JSON.stringify(currentFileJSON)], { type: 'text/plain' });

                        fileWriter.write(blob);
                        callback({ "message": "Import Successful" });
                    }, errorHandler);
                };

                reader.readAsText(file);
            }, errorHandler);

        }, errorHandler);
    }, errorHandler);
}


function resetWorkAllocations(callback) {
    window.webkitRequestFileSystem(window.PERSISTENT, 2048 * 2048, function (fs) {
        fs.root.getFile('saved_work_allocation.txt', { create: true }, function (fileEntry) {

            fileEntry.file(function (file) {
                var reader = new FileReader();

                reader.onloadend = function (e) {
                    // Create a FileWriter object for our FileEntry (log.txt).
                    fileEntry.createWriter(function (fileWriter) {
                        fileWriter.seek(0);
                        fileWriter.truncate(0);
                        fileWriter.onwriteend = function (e) {
                            console.log('Write completed.');
                            callback({ "message": "Import Successful" });
                        };

                        fileWriter.onerror = function (e) {
                            console.log('Write failed: ' + e.toString());
                        };

                        // Create a new Blob and write it to log.txt.
                        //var blob = new Blob([""], {type: 'text/plain'});

                        //fileWriter.write(blob);
                    }, errorHandler);
                };

                reader.readAsText(file);
            }, errorHandler);

        }, errorHandler);
    }, errorHandler);
}

function deleteSavedWorkAllocation(allocationId, callback) {
    sendFileData = function (allocationList) {
        console.log(allocationList);
        console.log("Here");
        delete allocationList[allocationId];
        resetWorkAllocations(function (resp) {
            console.log("Cleared");
            importWorkAllocations("", allocationList, callback);
        });
    }
    window.webkitRequestFileSystem(window.PERSISTENT, 2048 * 2048, onReadFs, errorHandler);
}

